NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream >> packet.packet_id;

    // Read username using length prefix
    stream.read_prefixed(packet.username);

    // Read scores vector (read_container handles count and elements)
    stream.read_container(packet.scores);

    // Read metadata as null-terminated string
    stream.read_null_terminated(packet.metadata);

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for packet_id (zero-copy view of first 4 bytes)
    auto id_span = stream.span(sizeof(uint32_t));
    info.packet_id = *reinterpret_cast<const uint32_t*>(id_span.data());

    // Read username using prefixed adaptor to get string_view
    std::string_view username_view;
    stream.read_prefixed(username_view);
    info.username = username_view;

    // Skip the scores vector (read count, then skip data)
    uint32_t score_count;
    stream >> score_count;
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}

