#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a buffer adaptor - we need a non-const reference for the adaptor
    // but the copy() operation won't modify the buffer content
    auto& mutable_buffer = const_cast<std::vector<uint8_t>&>(buffer);
    hexi::buffer_adaptor adaptor(mutable_buffer);

    // Create a destination vector to hold the peeked data
    std::vector<uint8_t> destination(bytes_to_peek);

    // Copy data without advancing the read pointer using the copy() method
    adaptor.copy(destination.data(), bytes_to_peek);

    // Return the peeked data
    return destination;
}

