#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Create buffer adaptor and stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Preview the first byte using buffer_adaptor without advancing stream
    if (buffer.size() < 1) {
        return result;
    }
    uint8_t preview_type = static_cast<uint8_t>(adaptor[0]);

    // Check available data size (at least header: data_type + item_count)
    if (buffer.size() < sizeof(uint8_t) + sizeof(uint32_t)) {
        return result;
    }

    // Read the header using binary_stream
    uint8_t data_type;
    uint32_t item_count;
    stream >> data_type >> item_count;

    result.data_type = data_type;

    // Calculate expected size and validate
    std::size_t header_size = sizeof(uint8_t) + sizeof(uint32_t);
    std::size_t item_size = (data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    std::size_t expected_size = header_size + item_count * item_size;

    if (buffer.size() < expected_size) {
        return result; // Not enough data
    }

    // Read items based on data type
    if (data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}

