    if (buffer.size() < required_space) {
        return false; // Insufficient space
    }

    // Create buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with no_throw to prevent exceptions
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Write header
    stream << header;

    // Write container data (items vector)
    stream.write_container(items);

    // Return true if write was successful, false otherwise
    return static_cast<bool>(stream);
}
```

