    std::cout << "\n--- Phase 2: Deallocating 3 blocks (push() to free list) ---" << std::endl;
    for (size_t i = 0; i < 3; ++i) {
        std::cout << "  Deallocating block at " << allocated_blocks[i] << std::endl;
        allocator.deallocate(allocated_blocks[i]);
    }

    std::cout << "\nAfter deallocations:" << std::endl;
    std::cout << "  Total deallocations: " << allocator.total_deallocs << std::endl;
    std::cout << "  Active blocks from storage: " << allocator.storage_active_count << std::endl;

    // Phase 3: Reallocate - demonstrates LIFO behavior (last deallocated = first reallocated)
    std::cout << "\n--- Phase 3: Allocating 2 blocks (pop() reuses deallocated blocks) ---" << std::endl;
    std::cout << "Note: Free list is LIFO - most recently deallocated blocks are reused first" << std::endl;
    for (size_t i = 0; i < 2; ++i) {
        auto* block = allocator.allocate(1);
        *block = (i + 10) * 100;
        std::cout << "  Allocated block at " << block << ", value: " << *block << std::endl;
        allocated_blocks.push_back(block);
    }

    std::cout << "\nAfter re-allocations:" << std::endl;
    std::cout << "  Total allocations: " << allocator.total_allocs << std::endl;
    std::cout << "  Active blocks from storage: " << allocator.storage_active_count << std::endl;

    // Phase 4: Clean up all remaining allocated blocks
    std::cout << "\n--- Phase 4: Cleanup (deallocating remaining blocks) ---" << std::endl;
    for (size_t i = 3; i < allocated_blocks.size(); ++i) {
        allocator.deallocate(allocated_blocks[i]);
    }

    std::cout << "\nFinal state (all blocks returned to free list):" << std::endl;
    std::cout << "  Total allocations: " << allocator.total_allocs << std::endl;
    std::cout << "  Total deallocations: " << allocator.total_deallocs << std::endl;
    std::cout << "  Active blocks from storage: " << allocator.storage_active_count << std::endl;
    std::cout << "  Active blocks from new: " << allocator.new_active_count << std::endl;

    std::cout << "\n=== Summary ===" << std::endl;
    std::cout << "The free list is managed as a LIFO (Last-In-First-Out) structure:" << std::endl;
    std::cout << "  - allocate() calls pop() to remove the head block from free list" << std::endl;
    std::cout << "  - deallocate() calls push() to add the block to free list head" << std::endl;
    std::cout << "  - This ensures O(1) allocation and deallocation performance" << std::endl;
}
```

This implementation demonstrates:

1. **Free list initialization**: The block_allocator starts with a pre-allocated pool of blocks in the free list
2. **pop() behavior**: Each `allocate()` call removes a block from the head of the free list
3. **push() behavior**: Each `deallocate()` call adds a block back to the head of the free list
4. **LIFO ordering**: The free list operates as a stack - most recently deallocated blocks are reused first
5. **Performance metrics**: Tracking allocation/deallocation counts and active block counts to observe the internal state

