std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file buffer for the specified file
    hexi::file_buffer file(file_path.string());

    // Prepare a vector to hold the header data
    std::vector<uint8_t> header(header_size);

    // Read the header data from the file
    // Note: file_buffer uses char* for read operations
    auto bytes_read = file.read(reinterpret_cast<char*>(header.data()), header_size);

    // Resize to actual bytes read (in case file is smaller than requested size)
    header.resize(bytes_read);

    // Return the header data
    // The file_buffer is automatically closed when it goes out of scope,
    // ensuring no persistent read pointer is maintained
    return header;
}
```

