    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using unsigned_type = std::make_unsigned_t<T>;
    unsigned_type result = 0;
    int shift = 0;
    std::uint8_t byte;

    // Read bytes until we find one without continuation bit
    do {
        reader >> byte;
        result |= static_cast<unsigned_type>(byte & 0x7F) << shift;
        shift += 7;
    } while (byte & 0x80);  // Continue if MSB is set

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer for encoding
    std::vector<std::uint8_t> buffer;

    // Encode the value
    {
        hexi::pmc::buffer_adaptor write_adaptor(buffer);
        hexi::pmc::binary_stream_writer writer(write_adaptor);
        encode_varint(writer, original_value);
    }

    // Decode the value
    T decoded_value;
    {
        hexi::pmc::buffer_adaptor read_adaptor(buffer);
        hexi::pmc::binary_stream_reader reader(read_adaptor);
        decoded_value = decode_varint<T>(reader);
    }

    // Verify roundtrip correctness
    return original_value == decoded_value;
}

