#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    std::size_t total_written = 0;

    for (const auto& chunk : chunks) {
        // Check available space before writing (calculate from buffer size and write offset)
        std::size_t available = adaptor.buffer_write_adaptor<std::vector<uint8_t>>::free();

        // Write the chunk
        adaptor.write(chunk.data(), chunk.size());
        total_written += chunk.size();
    }

    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    std::vector<uint8_t> result;

    while (read_adaptor.size() > 0) {
        // Determine how much to read (chunk_size or remaining)
        std::size_t to_read = std::min(chunk_size, read_adaptor.size());

        // Read the chunk
        std::vector<uint8_t> chunk(to_read);
        read_adaptor.read(chunk.data(), to_read);

        // Append to result
        result.insert(result.end(), chunk.begin(), chunk.end());
    }

    return result;
}

