#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    for (const auto& chunk : chunks) {
        // Check available space before writing
        std::size_t free_space = adaptor.free();

        // Write the chunk
        adaptor.write(chunk.data(), chunk.size());
    }

    // Return the final buffer size
    return buffer.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    std::vector<uint8_t> result;
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    // Read until buffer is empty
    while (!adaptor.empty()) {
        // Determine how much to read (only a portion at a time)
        std::size_t to_read = std::min(chunk_size, adaptor.size());

        // Prepare temporary buffer for this chunk
        std::vector<uint8_t> temp(to_read);

        // Read the chunk
        adaptor.read(temp.data(), to_read);

        // Append to result
        result.insert(result.end(), temp.begin(), temp.end());

        // Check remaining data after each read
        std::size_t remaining = adaptor.size();
    }

    return result;
}
