#include <gtest/gtest.h>
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <span>

// Include the implementation
#include "implementation.hpp"

TEST(ProtocolPacket, SerializeDeserialize) {
    ProtocolPacket original;
    original.message_id = 0x12345678;
    original.data_values = {0xABCD, 0xEF01, 0x2345};
    original.checksum = 0x98765432;

    auto buffer = serialize_protocol_packet(original);
    ASSERT_FALSE(buffer.empty());

    ProtocolPacket deserialized = deserialize_protocol_packet(buffer);

    EXPECT_EQ(original.message_id, deserialized.message_id);
    EXPECT_EQ(original.data_values, deserialized.data_values);
    EXPECT_EQ(original.checksum, deserialized.checksum);
}

TEST(ProtocolPacket, SerializeDeserializeEmptyVector) {
    ProtocolPacket original;
    original.message_id = 0x11111111;
    original.data_values = {};
    original.checksum = 0x22222222;

    auto buffer = serialize_protocol_packet(original);

    ProtocolPacket deserialized = deserialize_protocol_packet(buffer);

    EXPECT_EQ(original.message_id, deserialized.message_id);
    EXPECT_TRUE(deserialized.data_values.empty());
    EXPECT_EQ(original.checksum, deserialized.checksum);
}

TEST(ProtocolPacket, ExtractHeader) {
    ProtocolPacket packet;
    packet.message_id = 0xABCDEF00;
    packet.data_values = {0x1234, 0x5678};
    packet.checksum = 0xDEADBEEF;

    auto buffer = serialize_protocol_packet(packet);

    ProtocolHeader header = extract_protocol_header(buffer);

    EXPECT_EQ(packet.message_id, header.message_id);
}

TEST(ProtocolPacket, BigEndianConversion) {
    ProtocolPacket packet;
    packet.message_id = 0x12345678;
    packet.data_values = {0xABCD, 0xEF01};
    packet.checksum = 0x98765432;

    auto buffer = serialize_protocol_packet(packet);

    // Verify that the data is stored in big-endian format
    // On little-endian systems, bytes will be swapped
    if constexpr (std::endian::native == std::endian::little) {
        // First 4 bytes should be message_id in big-endian
        EXPECT_EQ(0x12, buffer[0]);
        EXPECT_EQ(0x34, buffer[1]);
        EXPECT_EQ(0x56, buffer[2]);
        EXPECT_EQ(0x78, buffer[3]);
    }

    ProtocolPacket deserialized = deserialize_protocol_packet(buffer);
    EXPECT_EQ(packet.message_id, deserialized.message_id);
    EXPECT_EQ(packet.data_values, deserialized.data_values);
    EXPECT_EQ(packet.checksum, deserialized.checksum);
}

